const dashboard = $('Get Project List').first().json;
const hubspot = $('Get HubSpot Sync State').first().json;

const projects = dashboard.projects || [];
const hsStates = hubspot.sync_states || [];

// Check which entity types have never synced
const neverSynced = hsStates.filter(s => !s.last_synced_at).map(s => s.entity_type);
const lastSync = hsStates.filter(s => s.last_synced_at).reduce((max, s) => {
  const t = new Date(s.last_synced_at).getTime();
  return t > max.ts ? { ts: t, dt: s.last_synced_at } : max;
}, { ts: 0, dt: null });

const ageHours = lastSync.dt ? (Date.now() - lastSync.ts) / 3600000 : null;
const stale = ageHours && ageHours > 48;

const issues = [];
if (neverSynced.length > 0) issues.push(`HubSpot never synced: ${neverSynced.join(', ')}`);
if (stale) issues.push(`HubSpot last sync ${Math.round(ageHours)}h ago — trigger /connectors/hubspot/sync`);
if (projects.length === 0) issues.push('No projects found in dashboard');

const summary = issues.length > 0 ? issues.join(' | ') : `HubSpot current (${Math.round(ageHours || 0)}h ago) | ${projects.length} projects active`;

return [{ json: { hasIssues: issues.length > 0, issues, summary, project_count: projects.length, never_synced: neverSynced } }];
